def _cleanup_loop(self, ttl=3600):
    while True:
        now = time.time()
        expired_ids = [tid for tid, task in self._instances.items() 
                       if now - task['timestamp'] > ttl]
        for tid in expired_ids:
            task = self._instances.pop(tid)
            if 'temp_dir_obj' in task:
                task['temp_dir_obj'].cleanup() # 物理删除临时沙盒
        time.sleep(600) # 每10分钟扫描一次

