import subprocess
import os

def format_latex_path(path):
    # 转换分隔符并转义下划线
    return path.replace('\\', '/').replace('_', '\\_')

def check_latex_env(required_packages=['longtable', 'subcaption']):
    results = {'pdflatex': False, 'packages': {}}
    try:
        subprocess.run(['pdflatex', '--version'], capture_output=True, check=True)
        results['pdflatex'] = True
    except:
        return "Error: pdflatex not found."

    for pkg in required_packages:
        check = subprocess.run(['kpsewhich', f'{pkg}.sty'], capture_output=True)
        results['packages'][pkg] = (check.returncode == 0)
    return results

